// Java Bytecode Analyzer and Optimizer using ASM library structure
import java.io.*;
import java.util.*;
import org.objectweb.asm.*;
import org.objectweb.asm.tree.*;
import org.objectweb.asm.tree.analysis.*;

public class BytecodeOptimizer {
    public static void main(String[] args) throws Exception {
        if (args.length < 1) return;
        ClassReader reader = new ClassReader(new FileInputStream(args[0]));
        ClassNode classNode = new ClassNode();
        reader.accept(classNode, 0);
        for (MethodNode method : classNode.methods) {
            optimize(method);
        }
        ClassWriter writer = new ClassWriter(ClassWriter.COMPUTE_FRAMES);
        classNode.accept(writer);
        try (FileOutputStream fos = new FileOutputStream("optimized_" + args[0])) {
            fos.write(writer.toByteArray());
        }
    }

    public static void optimize(MethodNode method) {
        boolean changed = true;
        while (changed) {
            changed = foldConstants(method);
            changed |= eliminateDeadCode(method);
        }
    }

    private static boolean foldConstants(MethodNode method) {
        boolean changed = false;
        InsnList instructions = method.instructions;
        for (AbstractInsnNode insn = instructions.getFirst(); insn != null; insn = insn.getNext()) {
            if (insn.getOpcode() == Opcodes.IADD && insn.getPrevious() != null && insn.getPrevious().getPrevious() != null) {
                AbstractInsnNode prev1 = insn.getPrevious();
                AbstractInsnNode prev2 = prev1.getPrevious();
                if (isPush(prev1) && isPush(prev2)) {
                    int val1 = getPushValue(prev1);
                    int val2 = getPushValue(prev2);
                    instructions.remove(prev2);
                    instructions.remove(prev1);
                    instructions.set(insn, new LdcInsnNode(val1 + val2));
                    changed = true;
                }
            }
        }
        return changed;
    }

    private static boolean eliminateDeadCode(MethodNode method) {
        boolean changed = false;
        InsnList instructions = method.instructions;
        for (AbstractInsnNode insn = instructions.getFirst(); insn != null; ) {
            AbstractInsnNode next = insn.getNext();
            if (insn.getOpcode() == Opcodes.NOP) {
                instructions.remove(insn);
                changed = true;
            }
            insn = next;
        }
        return changed;
    }

    private static boolean isPush(AbstractInsnNode insn) {
        int op = insn.getOpcode();
        return (op >= Opcodes.ICONST_M1 && op <= Opcodes.ICONST_5) || op == Opcodes.BIPUSH || op == Opcodes.SIPUSH || op == Opcodes.LDC;
    }

    private static int getPushValue(AbstractInsnNode insn) {
        int op = insn.getOpcode();
        if (op >= Opcodes.ICONST_M1 && op <= Opcodes.ICONST_5) return op - Opcodes.ICONST_0;
        if (insn instanceof IntInsnNode) return ((IntInsnNode) insn).operand;
        if (insn instanceof LdcInsnNode) return (Integer) ((LdcInsnNode) insn).cst;
        return 0;
    }
}
