// Distributed search engine with crawler, inverted index, and TF-IDF ranking
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;
import java.net.URL;
import java.io.*;

class SearchEngine {
    private final ConcurrentHashMap<String, ConcurrentHashMap<String, Integer>> index = new ConcurrentHashMap<>();
    private final ConcurrentHashMap<String, Integer> docLengths = new ConcurrentHashMap<>();
    private final AtomicInteger totalDocs = new AtomicInteger(0);

    public void indexDocument(String docId, String content) {
        String[] tokens = content.toLowerCase().split("\\W+");
        docLengths.put(docId, tokens.length);
        for (String token : tokens) {
            index.computeIfAbsent(token, k -> new ConcurrentHashMap<>())
                 .merge(docId, 1, Integer::sum);
        }
        totalDocs.incrementAndGet();
    }

    public Map<String, Double> search(String query) {
        String[] terms = query.toLowerCase().split("\\W+");
        Map<String, Double> scores = new HashMap<>();
        for (String term : terms) {
            if (!index.containsKey(term)) continue;
            double idf = Math.log((double) totalDocs.get() / (1 + index.get(term).size()));
            index.get(term).forEach((docId, tf) -> {
                double score = (double) tf / docLengths.get(docId) * idf;
                scores.merge(docId, score, Double::sum);
            });
        }
        return scores;
    }
}

class Crawler {
    private final SearchEngine engine;
    private final Set<String> visited = ConcurrentHashMap.newKeySet();
    private final ExecutorService executor = Executors.newFixedThreadPool(4);

    public Crawler(SearchEngine engine) { this.engine = engine; }

    public void crawl(String url) {
        executor.submit(() -> {
            if (visited.add(url)) {
                try {
                    Thread.sleep(1000); // Rate limiting
                    String content = fetchContent(url);
                    engine.indexDocument(url, content);
                } catch (Exception e) { }
            }
        });
    }

    private String fetchContent(String url) throws IOException {
        try (Scanner scanner = new Scanner(new URL(url).openStream())) {
            StringBuilder sb = new StringBuilder();
            while (scanner.hasNext()) sb.append(scanner.next()).append(" ");
            return sb.toString();
        }
    }
}

public class Main {
    public static void main(String[] args) {
        SearchEngine engine = new SearchEngine();
        Crawler crawler = new Crawler(engine);
        crawler.crawl("http://example.com");
    }
