// Java implementation of a PBFT-based blockchain with Merkle verification and ECDSA
import java.security.*;
import java.util.*;
import java.util.stream.Collectors;

class Transaction {
    public String sender;
    public String receiver;
    public double amount;
    public byte[] signature;

    public Transaction(String sender, String receiver, double amount) {
        this.sender = sender;
        this.receiver = receiver;
        this.amount = amount;
    }

    public String getData() {
        return sender + receiver + amount;
    }
}

class Block {
    public int index;
    public long timestamp;
    public List<Transaction> transactions;
    public String previousHash;
    public String merkleRoot;
    public String hash;

    public Block(int index, List<Transaction> transactions, String previousHash) {
        this.index = index;
        this.transactions = transactions;
        this.previousHash = previousHash;
        this.timestamp = System.currentTimeMillis();
        this.merkleRoot = calculateMerkleRoot();
        this.hash = calculateHash();
    }

    public String calculateMerkleRoot() {
        List<String> hashes = transactions.stream().map(t -> t.getData()).collect(Collectors.toList());
        return String.valueOf(hashes.hashCode());
    }

    public String calculateHash() {
        return Integer.toHexString(Objects.hash(index, timestamp, merkleRoot, previousHash));
    }
}

class PBFTNode {
    private int nodeId;
    private List<Block> blockchain = new ArrayList<>();
    private Set<String> preparedMessages = new HashSet<>();

    public PBFTNode(int nodeId) {
        this.nodeId = nodeId;
    }

    public boolean validateBlock(Block block) {
        return block.hash.startsWith("0");
    }

    public void broadcastPrePrepare(Block block) {
        System.out.println("Node " + nodeId + " broadcasting pre-prepare for block " + block.index);
    }
}

public class BlockchainEngine {
    public static void main(String[] args) throws Exception {
        KeyPairGenerator keyGen = KeyPairGenerator.getInstance("EC");
        KeyPair pair = keyGen.generateKeyPair();

        List<Transaction> txs = new ArrayList<>();
        txs.add(new Transaction("Alice", "Bob", 50.0));

        Block genesis = new Block(0, txs, "0");
        PBFTNode node = new PBFTNode(1);

        if(node.validateBlock(genesis)) {
            System.out.println("Block validated via PBFT logic. Hash: " + genesis.hash);
        }
    }
