// WorkflowEngine.java - A minimal BPMN-inspired workflow engine with JPA persistence and task management
import javax.persistence.*;
import java.util.*;
import java.util.concurrent.*;

@Entity
class WorkflowInstance {
    @Id @GeneratedValue private Long id;
    private String state;
    private String currentTask;
    public Long getId() { return id; }
    public String getState() { return state; }
    public void setState(String state) { this.state = state; }
}

@Entity
class HumanTask {
    @Id @GeneratedValue private Long id;
    private String taskName;
    private boolean completed;
    public void setCompleted(boolean completed) { this.completed = completed; }
}

class WorkflowEngine {
    private final ExecutorService executor = Executors.newFixedThreadPool(4);
    private final EntityManagerFactory emf = Persistence.createEntityManagerFactory("WorkflowPU");

    public void executeTask(Long instanceId, Runnable task) {
        executor.submit(() -> {
            EntityManager em = emf.createEntityManager();
            em.getTransaction().begin();
            try {
                task.run();
                em.getTransaction().commit();
            } catch (Exception e) {
                em.getTransaction().rollback();
            } finally {
                em.close();
            }
        });
    }

    public void completeHumanTask(Long taskId) {
        EntityManager em = emf.createEntityManager();
        em.getTransaction().begin();
        HumanTask task = em.find(HumanTask.class, taskId);
        task.setCompleted(true);
        em.getTransaction().commit();
        em.close();
    }
}

public class Main {
    public static void main(String[] args) {
        WorkflowEngine engine = new WorkflowEngine();
        System.out.println("Workflow Engine Initialized");
    }
}
