// Java static analysis tool for SQLi and XSS detection using AST parsing
import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.MethodCallExpr;
import java.io.File;
import java.util.Arrays;
import java.util.List;

public class SimpleSAST {
    private static final List<String> SQL_SINKS = Arrays.asList("executeQuery", "executeUpdate", "prepareStatement");
    private static final List<String> XSS_SINKS = Arrays.asList("println", "write", "print");

    public static void main(String[] args) throws Exception {
        File projectDir = new File("src/main/java");
        analyzeDirectory(projectDir);
    }

    private static void analyzeDirectory(File dir) throws Exception {
        for (File file : dir.listFiles()) {
            if (file.isDirectory()) analyzeDirectory(file);
            else if (file.getName().endsWith(".java")) {
                CompilationUnit cu = StaticJavaParser.parse(file);
                cu.findAll(MethodDeclaration.class).forEach(method -> {
                    method.findAll(MethodCallExpr.class).forEach(call -> {
                        checkVulnerabilities(call, method);
                    });
                });
            }
        }
    }

    private static void checkVulnerabilities(MethodCallExpr call, MethodDeclaration method) {
        String methodName = call.getNameAsString();

        if (SQL_SINKS.contains(methodName)) {
            call.getArguments().forEach(arg -> {
                if (isTainted(arg, method)) {
                    System.out.println("VULNERABILITY: Potential SQL Injection in " + method.getNameAsString() + " at line " + call.getBegin().get().line);
                }
            });
        }

        if (XSS_SINKS.contains(methodName)) {
            call.getArguments().forEach(arg -> {
                if (isTainted(arg, method)) {
                    System.out.println("VULNERABILITY: Potential XSS in " + method.getNameAsString() + " at line " + call.getBegin().get().line);
                }
            });
        }
    }

    private static boolean isTainted(Object expr, MethodDeclaration method) {
        String source = expr.toString();
        // Taint tracking: check if argument comes from method parameters (HTTP request inputs)
        return method.getParameters().stream().anyMatch(p -> p.getNameAsString().equals(source));
    }
