class Entity {
    int id;
    float x, y;
    byte[] lastState;
    public Entity(int id, float x, float y) { this.id = id; this.x = x; this.y = y; }
}

class SpatialGrid {
    private final Map<Integer, List<Entity>> grid = new ConcurrentHashMap<>();
    private final float cellSize = 100.0f;

    public void update(Entity e) {
        int gx = (int)(e.x / cellSize);
        int gy = (int)(e.y / cellSize);
        int key = Objects.hash(gx, gy);
        grid.computeIfAbsent(key, k -> new CopyOnWriteArrayList<>()).add(e);
    }
}

class GameServer {
    private final SpatialGrid world = new SpatialGrid();
    private final ScheduledExecutorService scheduler = Executors.newSingleThreadScheduledExecutor();

    public void start(int port) throws Exception {
        EventLoopGroup boss = new NioEventLoopGroup(1);
        EventLoopGroup worker = new NioEventLoopGroup();
        try {
            ServerBootstrap b = new ServerBootstrap();
            b.group(boss, worker).channel(NioServerSocketChannel.class)
             .childHandler(new ChannelInitializer<SocketChannel>() {
                 @Override
                 public void initChannel(SocketChannel ch) {
                     ch.pipeline().addLast(new GameHandler());
                 }
             });
            b.bind(port).sync().channel().closeFuture().sync();
        } finally {
            boss.shutdownGracefully();
            worker.shutdownGracefully();
        }
    }

