// Simple LSM-Tree Key-Value Store implementation in Java
import java.io.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.locks.*;

public class LSMStore {
    private final ConcurrentSkipListMap<String, String> memTable = new ConcurrentSkipListMap<>();
    private final ReentrantReadWriteLock lock = new ReentrantReadWriteLock();
    private final String walPath = "store.wal";
    private final int memTableThreshold = 1000;

    public void put(String key, String value) throws IOException {
        lock.writeLock().lock();
        try {
            writeToWAL(key, value);
            memTable.put(key, value);
            if (memTable.size() >= memTableThreshold) {
                flushToSSTable();
            }
        } finally {
            lock.writeLock().unlock();
        }
    }

    public String get(String key) {
        lock.readLock().lock();
        try {
            String val = memTable.get(key);
            if (val != null) return val;
            return searchSSTables(key);
        } finally {
            lock.readLock().unlock();
        }
    }

    private void writeToWAL(String key, String value) throws IOException {
        try (FileWriter fw = new FileWriter(walPath, true);
             BufferedWriter bw = new BufferedWriter(fw)) {
            bw.write(key + ":" + value + "\n");
        }
    }

    private void flushToSSTable() throws IOException {
        String fileName = "sst_" + System.currentTimeMillis() + ".db";
        try (PrintWriter out = new PrintWriter(new FileWriter(fileName))) {
            for (Map.Entry<String, String> entry : memTable.entrySet()) {
                out.println(entry.getKey() + ":" + entry.getValue());
            }
        }
        memTable.clear();
        new File(walPath).delete();
    }

    private String searchSSTables(String key) {
        File dir = new File(".");
        File[] files = dir.listFiles((d, name) -> name.startsWith("sst_"));
        if (files == null) return null;
        Arrays.sort(files, (a, b) -> b.getName().compareTo(a.getName()));
        for (File file : files) {
            try (BufferedReader reader = new BufferedReader(new FileReader(file))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    String[] parts = line.split(":");
                    if (parts[0].equals(key)) return parts[1];
                }
            } catch (IOException e) { continue; }
        }
        return null;
    }

    public static void main(String[] args) throws Exception {
        LSMStore store = new LSMStore();
        store.put("user:1", "Alice");
        System.out.println("Get user:1 -> " + store.get("user:1"));
    }
